$images = Get-ChildItem -Path images; $htmlFiles = Get-ChildItem -Filter *.html; foreach ($img in $images) { $oldName = $img.Name; $newName = $oldName.ToLower() -replace '[\s\(\)-]+', '_' -replace '_+', '_' -replace '_\.', '.'; if ($oldName -cne $newName) { Rename-Item -Path $img.FullName -NewName $newName; foreach ($html in $htmlFiles) { $content = Get-Content $html.FullName -Raw; $encodedName = $oldName -replace ' ', '%20'; $content = $content -replace [regex]::Escape("images/$oldName"), "images/$newName"; $content = $content -replace [regex]::Escape("images/$encodedName"), "images/$newName"; Set-Content -Path $html.FullName -Value $content -NoNewline } } }
